import { Workout, WorkoutRequest } from './schemas';

type ExerciseTemplate = {
  name: string;
  sets: string;
  reps?: string;
  duration?: string;
  rest: string;
  instructions: string;
};

const WARMUP: ExerciseTemplate[] = [
  { name: 'Jumping Jacks', sets: '1', duration: '90s', rest: '15s', instructions: 'Setup: Stand tall with your feet together, toes pointing forward, and arms resting naturally at your sides. Execution: In one fluid, explosive movement, jump your feet out slightly wider than shoulder-width while sweeping your arms out and up until your hands meet above your head. Immediately jump your feet back together and bring your arms back down to your sides. Breathing: Breathe in a steady, rhythmic pattern, inhaling as your feet jump out and exhaling as you return to the start. Tip: Keep your knees slightly bent to absorb impact on landing, and land softly on the balls of your feet.' },
  { name: 'Arm Circles', sets: '1', duration: '45s', rest: '10s', instructions: 'Setup: Stand tall with your feet shoulder-width apart, knees slightly bent, and your arms extended straight out to the sides at shoulder height, palms facing down. Execution: Keeping your shoulders down and back, make slow, controlled circular motions with your arms, drawing circles of moderate size in the air. Reverse the direction of the circles halfway through the set. Breathing: Inhale for one full circle, and exhale for the next circle, maintaining a slow and steady breathing cadence. Tip: Keep your core braced and torso completely still; do not let your back arch or ribcage flare.' },
  { name: 'Hip Circles', sets: '1', duration: '45s', rest: '10s', instructions: 'Setup: Stand with your feet slightly wider than shoulder-width apart, knees soft, and place both hands firmly on your hips. Execution: Keep your chest up and torso relatively still as you push your hips forward, to the side, backward, and to the other side in a large, slow, continuous circle. Reverse the direction halfway through. Breathing: Breathe deeply and naturally, coordinating your inhalations and exhalations with each rotation. Tip: Keep the movement smooth and continuous, focusing on mobilizing your hip joints and lower back.' },
  { name: 'Leg Swings', sets: '1', duration: '45s', rest: '10s', instructions: 'Setup: Stand tall next to a wall or a sturdy object, placing your hand on it for support. Keep your standing leg slightly bent and active. Execution: Swing your opposite leg forward and backward in a smooth, controlled arc, keeping the leg straight. Gradually increase the range of motion as your hips warm up. Complete all reps on one side, then switch. Breathing: Exhale as you swing your leg forward, inhale as you swing it backward. Tip: Keep your torso upright and engage your core to prevent your lower back from arching excessively at the top of the swing.' },
  { name: 'Inchworm', sets: '1', reps: '5', rest: '15s', instructions: 'Setup: Stand tall with your feet hip-width apart and arms at your sides. Execution: Hinge at your hips and bend forward to touch the floor with your hands, bending your knees slightly if needed. Walk your hands forward one step at a time until your body is in a straight line in a full plank position. Pause for a second, then walk your feet forward towards your hands in small steps, keeping your legs as straight as possible, until you return to a forward fold. Roll up to a standing position. Breathing: Inhale as you bend forward, hold your breath or breathe steadily as you walk your hands out, and exhale as you walk your feet back in. Tip: Engage your core throughout the movement to protect your spine, and do not let your hips sag when in the plank position.' },
];

const COOLDOWN: ExerciseTemplate[] = [
  { name: "Child's Pose", sets: '1', duration: '60s', rest: '0s', instructions: 'Setup: Kneel flat on the floor, bring your big toes together to touch, and sit your hips back onto your heels. Separate your knees about hip-width or chest-width apart. Execution: Extend your torso forward and down between your thighs, walking your hands out in front of you along the floor. Rest your forehead gently on the ground, allowing your chest and shoulders to melt toward the floor. Breathing: Inhale deeply into your belly and lower back, and exhale fully, allowing your hips to sink deeper into your heels with every breath. Tip: If your forehead does not comfortably touch the floor, rest it on a block or a rolled-up towel to keep your neck relaxed.' },
  { name: 'Seated Hamstring Stretch', sets: '1', duration: '45s', rest: '0s', instructions: 'Setup: Sit tall on the floor with one leg extended straight in front of you. Bend your opposite knee and place the sole of that foot flat against your inner thigh. Execution: Hinge forward from your hips, keeping your back flat and neck aligned with your spine. Reach both hands toward your extended leg\'s shin, ankle, or toes until you feel a gentle stretch along the back of your leg. Hold without bouncing, then switch sides. Breathing: Inhale to find length in your spine, and exhale to fold slightly deeper into the stretch under control. Tip: Do not round your upper back or pull with your neck; the movement should come entirely from your pelvis and hips.' },
  { name: 'Chest Opener Stretch', sets: '1', duration: '45s', rest: '0s', instructions: 'Setup: Stand tall with your feet shoulder-width apart, knees slightly bent, and your chest proud. Execution: Reach both arms behind your back and interlace your fingers. Straighten your arms fully, and gently pull your shoulders back and down while lifting your chest up toward the ceiling. Hold the stretch, keeping your head neutral. Breathing: Breathe deeply and slowly into your chest, feeling the ribcage expand with every inhalation. Tip: If your hands cannot touch or interlace behind your back, hold a strap or towel between them to perform the stretch.' },
  { name: 'Standing Quad Stretch', sets: '1', duration: '30s', rest: '0s', instructions: 'Setup: Stand tall on your left leg, placing your left hand on a wall or sturdy chair for balance. Execution: Bend your right knee and raise your heel toward your glutes. Reach back with your right hand and grasp your right ankle. Keep your knees close together and push your hips slightly forward until you feel a deep stretch in the front of your thigh. Hold, then repeat on the other side. Breathing: Breathe slowly, steadily, and deeply throughout the stretch. Tip: Avoid arching your lower back; brace your core to keep your pelvis neutral and maximize the stretch in your quadriceps.' },
];

